// Solution
function insertNode(root, word) {
    if (word === '') return false;
    let node = root;
    for (let char of word) {
        if (!node.children[char]) {
            node.children[char] = {};
        }
        node = node.children[char];
    }
    node.word = word;
    return true;
}

